SELECT * FROM (
    SELECT A.*, ROWNUM AS RNUM
    FROM (
        SELECT *
        FROM WOORIDO.NOTIFICATIONS
        WHERE USER_ID = #{userId}

            AND TYPE IN

                #{type}



            AND IS_READ = 'Y''N'

        ORDER BY CREATED_AT DESC
    ) A
    WHERE ROWNUM <= (#{offset} + #{limit})
)
WHERE RNUM > #{offset}

